// Flatten all pages and keep only real team sites (drop the contentstorage/Designer noise).
const sites=[];
for(const it of $input.all()){
  for(const s of (it.json.value||[])){
    if((s.webUrl||'').includes('/sites/')) sites.push({id:s.id, displayName:s.displayName, webUrl:s.webUrl});
  }
}
return sites.map(s=>({json:s}));

// One flat list: every file matching the search, tagged with its site, newest first.
const sites=$('2. Real sites only').all().map(i=>i.json);
const hits=[];
$input.all().forEach((it,idx)=>{
  const s=sites[idx]||{};
  const vals=(it.json&&it.json.value)||[];
  for(const f of vals){
    hits.push({
      site:s.displayName||'',
      file:f.name||'',
      folder:((f.parentReference&&f.parentReference.path)||'').replace(/^\/drives\/[^/]+\/root:?/,''),
      modified:(f.lastModifiedDateTime||'').slice(0,10),
      fileUrl:f.webUrl||'',
      siteId:s.id||''
    });
  }
});
hits.sort((a,b)=>String(b.modified).localeCompare(String(a.modified)));
return hits.length?hits.map(h=>({json:h})):[{json:{note:"No files matching 'weekly' found — edit the q= in node 3 (e.g. 'report', 'status') and rerun."}}];
